import{_ as a,c as e,o as m,b as t}from"./app.aa61b5f3.js";const y='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 1-2","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 1-2","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-10T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/1-2/index.md"}',p={},s=t('<div class="stanza"><a href="#s3.1" id="s3.1" class="num">3.1</a><div class="sans"><p>\u0907\u0926\u093E\u0928\u0940\u092E\u093E\u0923\u0935\u094B\u092A\u093E\u092F\u0902 \u092A\u094D\u0930\u0924\u093F\u092A\u093F\u092A\u093E\u0926\u092F\u093F\u0937\u0941\u0930\u0923\u094B\u0903 \u0924\u093E\u0935\u0924\u094D\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u0926\u0930\u094D\u0936\u092F\u0924\u093F\u2014</p><blockquote><p><strong>\u0906\u0924\u094D\u092E\u093E \u091A\u093F\u0924\u094D\u0924\u092E\u094D\u0965\u0967\u0965</strong></p></blockquote><p>\u092F\u0926\u0947\u0924\u0926\u094D\u0935\u093F\u0937\u092F\u0935\u093E\u0938\u0928\u093E\u091A\u094D\u091B\u0941\u0930\u093F\u0924\u0924\u094D\u0935\u093E\u0928\u094D\u0928\u093F\u0924\u094D\u092F\u0902 \u0924\u0926\u0927\u094D\u092F\u0935\u0938\u093E\u092F\u093E\u0926\u093F\u0935\u094D\u092F\u093E\u092A\u093E\u0930\u092C\u0941\u0926\u094D\u0927\u094D\u092F\u0939\u0919\u094D\u0915\u0943\u0928\u094D\u092E\u0928\u094B\u0930\u0942\u092A\u0902 \u091A\u093F\u0924\u094D\u0924\u0902 \u0924\u0926\u0947\u0935\u093E\u0924\u0924\u093F \u091A\u093F\u0926\u093E\u0924\u094D\u092E\u0915\u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0916\u094D\u092F\u093E\u0924\u094D\u092F\u093E \u0938\u0924\u094D\u0924\u094D\u0935\u093E\u0926\u093F\u0935\u0943\u0924\u094D\u0924\u094D\u092F\u0935\u0932\u092E\u094D\u092C\u0928\u0947\u0928 \u092F\u094B\u0928\u0940\u0903 \u0938\u091E\u094D\u091A\u0930\u0924\u0940\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u093E\u0923\u0941\u0930\u093F\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u0928 \u0924\u0941 \u091A\u093F\u0926\u0947\u0915\u0930\u0942\u092A\u0938\u094D\u092F\u093E\u0938\u094D\u092F\u093E\u0924\u0928\u092E\u0938\u094D\u0924\u093F\u0964 \u0905\u0924 \u090F\u0935 \u091A\u0948\u0924\u0928\u094D\u092F\u092E\u093E\u0924\u094D\u092E\u093E (\u0967-\u0967) \u0907\u0924\u093F \u0938\u094D\u0935\u092D\u093E\u0935\u092D\u0942\u0924\u0924\u093E\u0924\u094D\u0924\u094D\u0935\u093F\u0915\u0948\u0924\u0924\u094D\u0938\u094D\u0935\u0930\u0942\u092A\u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u0928\u093E\u0936\u092F\u0947\u0928 \u092A\u0942\u0930\u094D\u0935\u092E\u093E\u0924\u094D\u092E\u093E \u0932\u0915\u094D\u0937\u093F\u0924\u0903\u0964 \u0907\u0926\u093E\u0928\u0940\u0902 \u0924\u094D\u0935\u0947\u0924\u0926\u0940\u092F\u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0935\u092D\u093E\u0938\u092A\u094D\u0930\u0927\u093E\u0928\u093E\u0923\u0935\u0926\u0936\u094C\u091A\u093F\u0924\u094D\u092F\u0947\u0928\u0947\u0924\u093F \u0928 \u092A\u0942\u0930\u094D\u0935\u093E\u092A\u0930\u0935\u0948\u0937\u092E\u094D\u092F\u092E\u094D\u0965\u0967\u0965</p></div><hr><div class="trans"><p>Id\u0101n\u012Bm\u0101\u1E47avop\u0101ya\u1E41 pratipip\u0101dayi\u1E63ura\u1E47o\u1E25 t\u0101vatsvar\u016Bpa\u1E41 dar\u015Bayati\u2014</p><blockquote><p><strong>\u0100tm\u0101 cittam||1||</strong></p></blockquote><p>Yadetadvi\u1E63ayav\u0101san\u0101cchuritatv\u0101nnitya\u1E41 tadadhyavas\u0101y\u0101divy\u0101p\u0101rabuddhyaha\u1E45k\u1E5Bnmanor\u016Bpa\u1E41 citta\u1E41 tadev\u0101tati cid\u0101tmakasvasvar\u016Bp\u0101khy\u0101ty\u0101 sattv\u0101div\u1E5Bttyavalambanena yon\u012B\u1E25 sa\xF1carat\u012Bty\u0101tm\u0101\u1E47urityartha\u1E25| Na tu cidekar\u016Bpasy\u0101sy\u0101tanamasti| Ata eva caitanyam\u0101tm\u0101 (1-1) iti svabh\u0101vabh\u016Btat\u0101ttvikaitatsvar\u016Bpapratip\u0101dan\u0101\u015Bayena p\u016Brvam\u0101tm\u0101 lak\u1E63ita\u1E25| Id\u0101n\u012B\u1E41 tvetad\u012Byasa\u1E45koc\u0101vabh\u0101sapradh\u0101n\u0101\u1E47avada\u015Baucityeneti na p\u016Brv\u0101paravai\u1E63amyam||1||</p></div><hr><p>\u0421\u0435\u0439\u0447\u0430\u0441 <em>(id\u0101n\u012Bm)</em>, [\u015Aiva,] \u0436\u0435\u043B\u0430\u044F \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C <em>(pratipip\u0101dayi\u1E63u\u1E25)</em> \u0410\u043D\u0430\u0432\u043E\u043F\u0430\u0439\u044E (\u0100\u1E47avop\u0101ya) <em>(\u0101\u1E47ava-up\u0101yam)</em><sup>1</sup>, \u0432\u043D\u0430\u0447\u0430\u043B\u0435 <em>(t\u0101vat)</em> \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 <em>(dar\u015Bayati)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-r\u016Bpam)</em> a\u1E47u, \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 --\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u042F-- <em>(a\u1E47o\u1E25)</em>\u2014</p><blockquote><p><strong>\u0418\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u042F <em>(\u0101tm\u0101)</em> [\u0435\u0441\u0442\u044C] \u0443\u043C <em>(cittam)</em>||1||</strong></p></blockquote><p>Citta --\u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0435-- <em>(cittam)</em> [\u2014 \u044D\u0442\u043E] \u0442\u043E <em>(etad)</em>, \u0447\u0442\u043E <em>(yad)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u043F\u043E\u043A\u0440\u044B\u0442\u044B\u043C <em>(\u0101cchuritatv\u0101t)</em> \u0436\u0435\u043B\u0430\u043D\u0438\u044F\u043C\u0438 <em>(v\u0101san\u0101)</em> \u043A \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C [\u0447\u0443\u0432\u0441\u0442\u0432] <em>(vi\u1E63aya)</em>, \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(r\u016Bpam)</em> buddhi --\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u0442.\u0435. \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 14-- <em>(buddhi)</em>, aha\u1E45k\u0101ra --\u044D\u0433\u043E, \u0442.\u0435. \u0442\u0430\u0442\u0442\u0432\u044B 15-- <em>(aha\u1E45k\u1E5Bt)</em> [\u0438] manas --\u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0443\u043C\u0430, \u0442.\u0435. \u0442\u0430\u0442\u0442\u0432\u044B 16-- <em>(manas)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nityam)</em> \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D\u044B \u0432 <em>(vy\u0101p\u0101ra)</em> \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 <em>(adhyavas\u0101ya)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u0438\u0445 <em>(tad)</em> --\u0432\u044B\u0448\u0435\u0443\u043A\u0430\u0437\u0430\u043D\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432--<sup>2</sup></p><p>. \u042D\u0442\u0430 \u0441\u0430\u043C\u0430\u044F [citta] <em>(tad eva)</em> [\u0435\u0441\u0442\u044C] \u0101tm\u0101 --\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u042F-- <em>(\u0101tm\u0101)</em>, [\u0438\u043B\u0438] a\u1E47u --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u0430\u0442\u043E\u043C, \u0442.\u0435. \u0412\u044B\u0441\u0448\u0435\u0435 \u042F, \u0443\u043C\u0435\u043D\u044C\u0448\u0435\u043D\u043D\u043E\u0435 \u0434\u043E \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(a\u1E47u\u1E25)</em> [\u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E,] \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u043E \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u0438\u0433\u043D\u043E\u0440\u0438\u0440\u0443\u0435\u0442 --\u0438\u0437-\u0437\u0430 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F-- <em>(akhy\u0101ty\u0101\u1E25)</em>, \u0447\u0442\u043E \u0435\u0433\u043E <em>(sva)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva- r\u016Bpa)</em> \u0435\u0441\u0442\u044C <em>(\u0101tmaka)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(cit)</em>, (\u0442\u043E) \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F <em>(atati)</em>, \u0442.\u0435. [\u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F] \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u0438\u0442 <em>(sa\xF1carati)</em> \u043A [\u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C] \u0444\u043E\u0440\u043C\u0430\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(yon\u012B\u1E25)</em>, \u0446\u0435\u043F\u043B\u044F\u044F\u0441\u044C <em>(avalambanena)</em> \u0437\u0430 \u0443\u0441\u043B\u043E\u0432\u0438\u044F, \u0438\u043B\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 <em>(v\u1E5Btti)</em> \u0421\u0430\u0442\u0442\u0432\u044B <em>(sattva)</em>, \u0438 \u0442.\u0434. <em>(\u0101di... iti)</em><sup>3</sup>. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em>|</p><p>[\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435,] \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na tu... asti)</em> \u0431\u043B\u0443\u0436\u0434\u0430\u043D\u0438\u044F <em>(atanam)</em> \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> [\u0101tm\u0101], \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0435 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A <em>(eka-r\u016Bpasya)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(cit)</em>|</p><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u0101tm\u0101 <em>(\u0101tm\u0101)</em> [\u0431\u044B\u043B] \u0440\u0430\u043D\u0435\u0435 <em>(p\u016Brvam)</em> \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D <em>(lak\u1E63ita\u1E25)</em> [\u043A\u0430\u043A] &quot;\u0412\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0435\u0435 \u0438 \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanyam)</em> [\u0435\u0441\u0442\u044C] \u0101tm\u0101 --\u0412\u044B\u0441\u0448\u0435\u0435 \u042F, \u0438\u043B\u0438 \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438-- <em>(\u0101tm\u0101 iti)</em>&quot;\u0432 I, 1 [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-1)</em>, \u0441 \u0446\u0435\u043B\u044C\u044E <em>(\u0101\u015Bayena)</em> \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044F <em>(pratip\u0101dana)</em> \u0435\u0433\u043E <em>(etad)</em> \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0439 <em>(t\u0101ttvika)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bh\u016Bta)</em> \u0435\u0433\u043E <em>(sva)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(bh\u0101va)</em>|</p><p>\u041D\u043E <em>(tu)</em> \u0441\u0435\u0439\u0447\u0430\u0441 <em>(id\u0101n\u012Bm)</em> [\u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0101tm\u0101] \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u043C <em>(aucityena)</em> \u043A [\u0435\u0433\u043E] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E <em>(da\u015B\u0101)</em> a\u1E47u --\u0442.\u0435. \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(\u0101\u1E47ava)</em>, [\u0432\u0441\u0435 \u044D\u0442\u043E] \u0433\u043B\u0430\u0432\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0441\u0432\u044F\u0437\u0430\u043D\u043E <em>(pradh\u0101na)</em> \u0441 \u0435\u0433\u043E <em>(etad\u012Bya)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C <em>(avabh\u0101sa)</em> \u0432 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0438\u043B\u0438 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0438 <em>(sa\u1E45koca)</em>. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(iti)</em>, \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0439 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u0432\u043E\u0441\u0442\u0438, \u0438\u043B\u0438 \u043D\u0435\u043A\u043E\u0440\u0440\u0435\u043A\u0442\u043D\u043E\u0441\u0442\u0438 <em>(vai\u1E63amyam)</em> \u043C\u0435\u0436\u0434\u0443 \u043F\u0440\u0435\u0436\u043D\u0438\u043C <em>(p\u016Brva)</em> [\u0438] \u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u0437\u0434\u043D\u0438\u043C [\u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u044F\u043C\u0438] <em>(apara)</em><sup>4</sup>||1||</p><hr><ol><li><p>\u0100\u1E47avop\u0101ya \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C\u0438, \u0438\u043C\u0435\u044E\u0449\u0438\u043C\u0438 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u043A a\u1E47u, \u0438\u043B\u0438 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0439 \u0441\u0430\u043C\u043E\u0441\u0442\u0438 (\u0442.\u0435. \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u043C\u0443 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443). \u0418\u0442\u0430\u043A, \u0442\u0440\u0435\u0442\u044C\u044F \u0413\u043B\u0430\u0432\u0430, \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u0430\u044F \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u0430\u043C, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0449\u0438\u043C \u0442\u043E\u0447\u043A\u0443 \u0437\u0440\u0435\u043D\u0438\u044F a\u1E47u, \u043D\u0430\u0447\u0430\u043B\u0430\u0441\u044C.</p></li><li><p>\u041F\u043E\u0434 &quot;\u0438 \u0442.\u0434.&quot; \u0430\u0432\u0442\u043E\u0440 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u044D\u0433\u043E \u0438 \u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0443\u043C\u0430. \u0412 \u0442\u043E \u0432\u0440\u0435\u043C\u044F\u043A\u043E\u0433\u0434\u0430 \u0431\u0443\u0434\u0434\u0445\u0438 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u0447\u0443\u0432\u0441\u0442\u0432, \u044D\u0433\u043E \u0437\u0430\u043D\u044F\u0442\u043E \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435\u043C \u043A \u043E\u0431\u043B\u0430\u0434\u0430\u043D\u0438\u044E \u0438\u043C\u0438 (\u0442.\u0435. \u044D\u0442\u0430 \u0432\u0435\u0449\u044C \u2014 \u043C\u043E\u044F). Manas (\u043C\u0430\u043D\u0430\u0441 - \u043E\u0431\u044B\u0447\u043D\u044B\u0439 \u0443\u043C) \u0435\u0441\u0442\u044C \u043D\u0438 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u0432\u0438\u043A\u0430\u043B\u044C\u043F\u044B (vikalpa-s), \u0438\u043B\u0438 \u043C\u044B\u0441\u043B\u0438 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0435 \u0441 \u044D\u0442\u0438\u043C\u0438 \u0441\u0430\u043C\u044B\u043C\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438. \u0412\u0441\u0435 \u0442\u0440\u0438 \u043E\u0431\u0440\u0430\u0437\u0443\u044E\u0442 \u0410\u043D\u0442\u0430\u0445\u043A\u0430\u0440\u0430\u043D\u0443 (Anta\u1E25kara\u1E47a), \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043E\u0440\u0433\u0430\u043D, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0441\u0438\u0441\u0442\u0435\u043C\u0435 \u0422\u0440\u0438\u043A\u0438. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, citta \u0437\u0434\u0435\u0441\u044C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0443\u043C\u043E\u043C&quot;, \u043D\u043E \u0432 \u0441\u043C\u044B\u0441\u043B\u0435 Anta\u1E25kara\u1E47a, \u0430 \u043D\u0435 \u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E manas. \u0412 \u044D\u0442\u043E\u043C \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0437\u043D\u0438\u0446\u0430 \u043C\u0435\u0436\u0434\u0443 citta \u0438 manas. \u041F\u043E\u043D\u044F\u0442\u043D\u043E? \u041E\u0442\u043B\u0438\u0447\u043D\u043E!</p></li><li><p>\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u0421\u0430\u0442\u0442\u0432\u044B (Sattva), \u0420\u0430\u0434\u0436\u0430\u0441\u0430 (Rajas) \u0438 \u0422\u0430\u043C\u0430\u0441\u0430 (Tamas).</p></li><li><p>\u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u043F\u043E\u0434 &quot;I, 1&quot; \u0430\u0432\u0442\u043E\u0440 \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442 \u043F\u0435\u0440\u0432\u044B\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u043F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F. \u0418 \u044D\u0442\u043E\u0442 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0442\u0430\u043A\u0436\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u044B\u043C \u043F\u0435\u0440\u0432\u044B\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u044B\u0445 \u015Aivas\u016Btra-s. \u0417\u0434\u0435\u0441\u044C, \u0432\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 &quot;\u0101tm\u0101&quot; \u0447\u0435\u0442\u043A\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A &quot;\u0412\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0435\u0435 \u0438 \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435&quot; (Caitanya). \u041E\u0434\u043D\u0430\u043A\u043E, \u0432 \u044D\u0442\u043E\u0439 \u0442\u0440\u0435\u0442\u044C\u0435\u0439 \u0413\u043B\u0430\u0432\u0435 \u0440\u0435\u0447\u044C \u043D\u0435 \u0438\u0434\u0435\u0442 \u043E &quot;\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438&quot; \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F, \u0430 \u0441\u043A\u043E\u0440\u0435\u0435 \u043E \u0435\u0433\u043E &quot;\u0101\u1E47avada\u015B\u0101&quot;, \u0438\u043B\u0438 &quot;\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 a\u1E47u, \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430&quot;. \u0412 \u044D\u0442\u0438\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445, \u0101tm\u0101 \u2014 \u044D\u0442\u043E \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435, \u0447\u0442\u043E \u0438 citta (\u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u044D\u0433\u043E \u0438 \u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0443\u043C\u0430). \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0432 \u0435\u0433\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438, \u0412\u044B\u0441\u0448\u0435\u0435 \u042F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0438 \u0447\u0435\u043C \u0438\u043D\u044B\u043C, \u043A\u0430\u043A \u0447\u0438\u0441\u0442\u044B\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C,\u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441 citta. \u0412\u043E\u043E\u0431\u0449\u0435 \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 &quot;\u0434\u0432\u0443\u0445&quot; \u0101tm\u0101-s, \u043E\u0434\u0438\u043D \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439, \u0430 \u0434\u0440\u0443\u0433\u043E\u0439 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439! \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u044F \u043C\u0435\u0436\u0434\u0443 \u0442\u0435\u043C, \u0447\u0442\u043E \u0437\u0430\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431 \u0101tm\u0101 \u0432 I, 1 \u0438 III, 1.</p></li></ol></div><div class="stanza"><a href="#s3.2" id="s3.2" class="num">3.2</a><div class="sans"><p>\u0905\u0938\u094D\u092F \u091A\u093F\u0924\u094D\u0924\u0938\u094D\u0935\u0930\u0942\u092A\u0938\u094D\u092F\u093E\u0923\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u0903\u2014</p><blockquote><p><strong>\u091C\u094D\u091E\u093E\u0928\u0902 \u092C\u0928\u094D\u0927\u0903\u0965\u0968\u0965</strong></p></blockquote><p>\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u092E\u094B\u0939\u092E\u092F\u093E\u0927\u094D\u092F\u0935\u0938\u093E\u092F\u093E\u0926\u093F\u0935\u0943\u0924\u094D\u0924\u093F\u0930\u0942\u092A\u0902 \u0924\u0926\u0941\u091A\u093F\u0924\u092D\u0947\u0926\u093E\u0935\u092D\u093E\u0938\u0928\u093E\u0924\u094D\u092E\u0915\u0902 \u092F\u091C\u094D\u091C\u094D\u091E\u093E\u0928\u0902 \u0924\u0926\u094D\u092C\u0928\u094D\u0927\u0903\u0964 \u0924\u0924\u094D\u092A\u093E\u0936\u093F\u0924\u0924\u094D\u0935\u093E\u0926\u0947\u0935 \u0939\u094D\u092F\u092F\u0902 \u0938\u0902\u0938\u0930\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0924\u0928\u094D\u0924\u094D\u0930\u0938\u0926\u094D\u092D\u093E\u0935\u0947</p><blockquote><p>\u0938\u0924\u094D\u0924\u094D\u0935\u0938\u094D\u0925\u094B \u0930\u093E\u091C\u0938\u0938\u094D\u0925\u0936\u094D\u091A \u0924\u092E\u0938\u094D\u0925\u094B \u0917\u0941\u0923\u0935\u0947\u0926\u0915\u0903\u0964<br> \u090F\u0935\u0902 \u092A\u0930\u094D\u092F\u091F\u0924\u0947 \u0926\u0947\u0939\u0940 \u0938\u094D\u0925\u093E\u0928\u093E\u0924\u094D\u0938\u094D\u0925\u093E\u0928\u093E\u0928\u094D\u0924\u0930\u0902 \u0935\u094D\u0930\u091C\u0928\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0924\u0926\u0947\u0935</p><blockquote><p>\u0924\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u094B\u0926\u092F\u0930\u0942\u092A\u0947\u0923 \u092E\u0928\u094B\u093D\u0939\u092E\u094D\u092C\u0941\u0926\u094D\u0927\u093F\u0935\u0930\u094D\u0924\u093F\u0928\u093E\u0964<br> \u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u0947\u0928 \u0938\u0902\u0930\u0941\u0926\u094D\u0927\u0938\u094D\u0924\u0926\u0941\u0924\u094D\u0925\u0902 \u092A\u094D\u0930\u0924\u094D\u092F\u092F\u094B\u0926\u094D\u092D\u0935\u092E\u094D\u0965<br> \u092D\u0941\u0919\u094D\u0915\u094D\u0924\u0947 \u092A\u0930\u0935\u0936\u094B \u092D\u094B\u0917\u0902 \u0924\u0926\u094D\u092D\u093E\u0935\u093E\u0924\u094D\u0938\u0902\u0938\u0930\u0947\u0924\u094D...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u093E\u0928\u0942\u0926\u093F\u0924\u092E\u094D\u0964</p><blockquote><p>... \u0905\u0924\u0903\u0964<br> \u0938\u0902\u0938\u0943\u0924\u093F\u092A\u094D\u0930\u0932\u092F\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u0915\u093E\u0930\u0923\u0902 \u0938\u092E\u094D\u092A\u094D\u0930\u091A\u0915\u094D\u0937\u094D\u092E\u0939\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0947\u0924\u0924\u094D\u092A\u094D\u0930\u0924\u093F\u0935\u093F\u0927\u093E\u0928\u093E\u092F \u0938\u094D\u092A\u0928\u094D\u0926\u0936\u093E\u0938\u094D\u0924\u094D\u0930\u0947\u0965\u0968\u0965</p></div><hr><div class="trans"><p>Asya cittasvar\u016Bpasy\u0101\u1E47v\u0101tmana\u1E25\u2014</p><blockquote><p><strong>J\xF1\u0101na\u1E41 bandha\u1E25||2||</strong></p></blockquote><p>Sukhadu\u1E25khamohamay\u0101dhyavas\u0101y\u0101div\u1E5Bttir\u016Bpa\u1E41 taducitabhed\u0101vabh\u0101san\u0101tmaka\u1E41 yajj\xF1\u0101na\u1E41 tadbandha\u1E25| Tatp\u0101\u015Bitatv\u0101deva hyaya\u1E41 sa\u1E41sarati| Tadukta\u1E41 \u015Br\u012Btantrasadbh\u0101ve</p><blockquote><p>Sattvastho r\u0101jasastha\u015Bca tamastho gu\u1E47avedaka\u1E25|<br> Eva\u1E41 parya\u1E6Date deh\u012B sth\u0101n\u0101tsth\u0101n\u0101ntara\u1E41 vrajan||</p></blockquote><p>iti| Etadeva</p><blockquote><p>Tanm\u0101trodayar\u016Bpe\u1E47a mano&#39;hambuddhivartin\u0101|<br> Purya\u1E63\u1E6Dakena sa\u1E41ruddhastaduttha\u1E41 pratyayodbhavam||<br> Bhu\u1E45kte parava\u015Bo bhoga\u1E41 tadbh\u0101v\u0101tsa\u1E41saret...|</p></blockquote><p>ityanen\u0101n\u016Bditam|</p><blockquote><p>... ata\u1E25|<br> Sa\u1E41s\u1E5Btipralayasy\u0101sya k\u0101ra\u1E47a\u1E41 sampracak\u1E63mahe||</p></blockquote><p>ityetatpratividh\u0101n\u0101ya spanda\u015B\u0101stre||2||</p></div><hr><p>\u0414\u043B\u044F \u044D\u0442\u043E\u0433\u043E [\u0101tm\u0101] <em>(asya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 [\u0442\u0435\u043F\u0435\u0440\u044C] \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(\u0101tmana\u1E25)</em> a\u1E47u, \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C <em>(a\u1E47u)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpasya)</em> \u0435\u0441\u0442\u044C citta <em>(citta)</em>\u2014</p><blockquote><p><strong>[\u041F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0443\u043C\u043E\u043C] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0440\u0430\u0431\u0441\u0442\u0432\u043E\u043C <em>(bandha\u1E25)</em>||2||</strong></p></blockquote><p>\u042D\u0442\u043E <em>(tad)</em> \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0440\u0430\u0431\u0441\u0442\u0432\u043E\u043C <em>(bandha\u1E25)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bpam)</em> \u2014 \u044D\u0442\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u044B <em>(v\u1E5Btti)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F <em>(adhyavas\u0101ya)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em><sup>1</sup>, \u043F\u043E\u043B\u043D\u044B\u0435 <em>(maya)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(sukha)</em>, \u0431\u043E\u043B\u0438 <em>(du\u1E25kha)</em> [\u0438] \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(moha)</em>, [\u0438] \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. \u0437\u043D\u0430\u043D\u0438\u0435-- \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(\u0101tmakam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(avabh\u0101sana)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 --\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438-- <em>(bheda)</em>, \u043F\u0440\u0438\u0441\u0443\u0449\u0438\u0445 <em>(ucita)</em> \u0438\u043C --\u0442.\u0435. \u0432\u044B\u0448\u0435\u0443\u043A\u0430\u0437\u0430\u043D\u043D\u044B\u043C \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C-- <em>(tad)</em>|</p><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u0442\u0430\u043A\u043E\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u0438\u043B\u0438 a\u1E47u] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043E \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(p\u0101\u015Bitatv\u0101t)</em> \u044D\u0442\u043E\u0433\u043E [\u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E \u0443\u043C\u043E\u043C \u0437\u043D\u0430\u043D\u0438\u044F] <em>(tad... eva)</em>, \u043E\u043D\u043E <em>(ayam)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0438\u0440\u0443\u0435\u0442 <em>(sa\u1E41sarati)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>!|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E [\u0442\u0430\u043A\u0436\u0435] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C Tantrasadbh\u0101va <em>(\u015Br\u012B-tantrasadbh\u0101ve)</em>:</p><blockquote><p>&quot;\u041F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 <em>(stha\u1E25)</em> \u0432 \u0421\u0430\u0442\u0442\u0432\u0435 (Sattva) <em>(sattva)</em>, \u0420\u0430\u0434\u0436\u0430\u0441\u0435 (Rajas) --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0439\u0441\u044F \u043A Rajas-- <em>(r\u0101jasa)</em> \u0438 <em>(ca)</em> \u0422\u0430\u043C\u0430\u0441\u0435 (Tamas) <em>(tama)</em>, [\u0438] \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439 <em>(vedaka\u1E25)</em> [\u0442\u043E\u043B\u044C\u043A\u043E] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0441\u0432\u043E\u0438\u0445] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(gu\u1E47a)</em>, \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u044B\u0439 <em>(deh\u012B)</em> \u0431\u043B\u0443\u0436\u0434\u0430\u0435\u0442 <em>(parya\u1E6Date)</em>, \u043F\u0435\u0440\u0435\u043C\u0435\u0449\u0430\u044F\u0441\u044C <em>(vrajan)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em> \u043E\u0442 \u043E\u0434\u043D\u043E\u0433\u043E \u043C\u0435\u0441\u0442\u0430 <em>(sth\u0101n\u0101t)</em> \u043A \u0434\u0440\u0443\u0433\u043E\u043C\u0443 <em>(antaram)</em> \u043C\u0435\u0441\u0442\u0443 <em>(sth\u0101na... iti)</em> --\u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0438 \u043C\u0435\u0442\u0430\u0444\u043E\u0440\u0438\u0447\u0435\u0441\u043A\u0438--<sup>2</sup>&quot;||</p></blockquote><p>\u0422\u0430 \u0436\u0435 \u0441\u0430\u043C\u0430\u044F [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(etad eva)</em> \u0431\u044B\u043B\u0430 \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0430 <em>(an\u016Bditam)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u044D\u0442\u043E\u0439 [\u0446\u0438\u0442\u0430\u0442\u044B] <em>(anena)</em>:</p><blockquote><p>&quot;\u041F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0435 \u0438 \u043E\u0445\u0432\u0430\u0447\u0435\u043D\u043D\u043E\u0435 <em>(sa\u1E41ruddha\u1E25)</em> Purya\u1E63\u1E6Daka <em>(purya\u1E63\u1E6Dakena)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(udaya-r\u016Bpe\u1E47a)</em> \u0438\u0437 [\u043F\u044F\u0442\u0438] \u0422\u0430\u043D\u043C\u0430\u0442\u0440 (Tanm\u0101tra-s) --\u0442.\u0435. \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432-- <em>(tanm\u0101tra)</em> [\u0438] \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(vartin\u0101)</em> \u0432 \u0443\u043C\u0435 <em>(manas)</em>, \u044D\u0433\u043E <em>(aham)</em> [\u0438] \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0435 <em>(buddhi)</em>, \u043F\u043E\u0434\u0447\u0438\u043D\u0435\u043D\u043D\u043E\u0435 [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u0438\u043B\u0438 \u043F\u0430\u0448\u0443 - pa\u015Bu] <em>(parava\u015Ba\u1E25)</em> \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 <em>(bhu\u1E45kte)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0438 \u0433\u0435\u043D\u0435\u0440\u0430\u0446\u0438\u044E <em>(udbhavam)</em> \u0438\u0434\u0435\u0439 <em>(pratyaya)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 <em>(uttham)</em> \u0438\u0437 \u044D\u0442\u043E\u0433\u043E [Purya\u1E63\u1E6Daka] <em>(tad)</em>, [\u0432\u043C\u0435\u0441\u0442\u0435 \u0441] \u0432\u043A\u0443\u0448\u0435\u043D\u0438\u0435\u043C [\u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F \u0438 \u0431\u043E\u043B\u0438, \u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438 \u0438\u0437 \u044D\u0442\u0438\u0445 \u0441\u0430\u043C\u044B\u0445 \u0438\u0434\u0435\u0439] <em>(bhogam)</em>. \u041E\u043D \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0438\u0440\u0443\u0435\u0442 <em>(sa\u1E41saret)</em> \u0438\u0437-\u0437\u0430 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0435\u043D\u0438\u044F <em>(bh\u0101v\u0101t)</em> \u044D\u0442\u043E\u0433\u043E [Purya\u1E63\u1E6Daka] <em>(tad... iti)</em>...&quot;|<br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 17 \u0438 \u0447\u0430\u0441\u0442\u044C 18]</p></blockquote><p>\u0412 \u041F\u0438\u0441\u0430\u043D\u0438\u0438 <em>(\u015B\u0101stre)</em>, \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u043C \u0421\u043F\u0430\u043D\u0434\u0435 <em>(spanda)</em> --\u043A\u043E\u0440\u043E\u0447\u0435, \u0432 Spandak\u0101rik\u0101-s--, \u0447\u0442\u043E\u0431\u044B \u0432\u043E\u0441\u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C <em>(pratividh\u0101n\u0101ya)</em> \u044D\u0442\u043E\u0439 [\u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438, \u0438\u043B\u0438 \u0421\u0430\u043C\u0441\u0430\u0440\u0435 - Sa\u1E41s\u0101ra] <em>(etad)</em> [\u0430\u0432\u0442\u043E\u0440 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442:]</p><blockquote><p>&quot;... \u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(atas)</em>, \u043C\u044B [\u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u043C] \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C <em>(sampracak\u1E63mahe)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u0443 <em>(k\u0101ra\u1E47am)</em> \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(pralayasya)</em> \u043F\u0435\u0440\u0435\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0439 <em>(sa\u1E41s\u1E5Bti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s, \u043E\u0441\u0442\u0430\u0432\u0448\u0430\u044F\u0441\u044F \u0447\u0430\u0441\u0442\u044C III, 18]</p></blockquote><p>||2||</p><hr><ol><li><p>\u0420\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0435\u0441\u0442\u044C \u0440\u0430\u0431\u043E\u0442\u0430 \u0431\u0443\u0434\u0434\u0445\u0438, \u0438\u043B\u0438 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430. \u041F\u043E\u0434 &quot;\u0438 \u0442.\u0434.&quot;\u0430\u0432\u0442\u043E\u0440 \u043C\u043E\u043B\u0447\u0430\u043B\u0438\u0432\u043E \u0441\u0441\u044B\u043B\u0430\u0435\u0442\u0441\u044F \u043D\u0430 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C &quot;\u043E\u0431\u044B\u0447\u043D\u043E\u0439 \u043C\u044B\u0441\u043B\u0438, \u043F\u043E\u043B\u043D\u043E\u0439 \u0444\u0430\u043D\u0442\u0430\u0437\u0438\u0439&quot; \u0438 &quot;\u0441\u0430\u043C\u043E\u043C\u043D\u0435\u043D\u0438\u0435&quot;, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u044B \u0434\u043B\u044F manas (\u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0443\u043C\u0430) \u0438 aha\u1E45k\u0101ra (\u044D\u0433\u043E). \u0412 \u043E\u0431\u0449\u0435\u043C, \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E citta, \u0442.\u0435. \u043E\u0431 anta\u1E25kara\u1E47a, \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u043E\u043C \u043E\u0440\u0433\u0430\u043D\u0435.</p></li><li><p>\u0418\u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0433\u043E\u0440\u043E\u0434\u0430 \u0432 \u0434\u0440\u0443\u0433\u043E\u0439, \u0438\u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0432 \u0434\u0440\u0443\u0433\u043E\u0435, \u043E\u0442 \u043E\u0434\u043D\u043E\u0433\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044F \u043A \u0434\u0440\u0443\u0433\u043E\u043C\u0443 \u0438 \u0442.\u0434. \u0412\u0441\u0435 \u044D\u0442\u043E \u0432\u0435\u0434\u0435\u0442 \u0432 \u043D\u0438\u043A\u0443\u0434\u0430!</p></li></ol></div>',2),i=[s];function o(r,u,n,d,v,c){return m(),e("div",null,i)}var k=a(p,[["render",o]]);export{y as __pageData,k as default};
